94	const ContractsTab = ({ workspaceId }: { workspaceId?: string } = {}) => {
95	  const [contracts, setContracts] = useState<Contract[]>([]);
96	  const [loading, setLoading] = useState(true);
97	  const [searchQuery, setSearchQuery] = useState("");
98	  const [statusFilter, setStatusFilter] = useState("all");
99	  const [sortBy, setSortBy] = useState<"newest" | "oldest" | "value">("newest");
100	  const { limits, isFree } = useSubscription();
101	  const [createDialogOpen, setCreateDialogOpen] = useState(false);
102	  const [editingContract, setEditingContract] = useState<Contract | null>(null);
103	  const [previewContract, setPreviewContract] = useState<Contract | null>(null);
104	  const [uploadDialogOpen, setUploadDialogOpen] = useState(false);
105	
106	  const fetchContracts = async () => {
107	    const { data: { session } } = await supabase.auth.getSession();
108	    if (!session) return;
109	
110	    if (workspaceId) {
111	      const { data: msgs } = await supabase
112	        .from("chat_messages")
113	        .select("contract_id")
114	        .eq("room_id", workspaceId)
115	        .not("contract_id", "is", null);
116	      const ids = [...new Set((msgs || []).map((m: any) => m.contract_id).filter(Boolean))];
117	      if (ids.length === 0) { setContracts([]); setLoading(false); return; }
118	      const { data, error } = await supabase.from("contracts").select("*").in("id", ids).order("created_at", { ascending: false });
119	      if (error) { toast.error("Failed to load contracts"); return; }
120	      setContracts(data || []);
121	      setLoading(false);
122	      return;
123	    }
124	
125	    const { data, error } = await supabase
126	      .from("contracts")
127	      .select("*")
128	      .eq("user_id", session.user.id)
129	      .order("created_at", { ascending: false });
130	
131	    if (error) {
132	      toast.error("Failed to load contracts");
133	      return;
134	    }
135	
136	    setContracts(data || []);
137	    setLoading(false);
138	  };
139	
140	  useEffect(() => {
141	    fetchContracts();
142	  }, [workspaceId]);
143	
144	  const handleDelete = async (id: string) => {
145	    const { error } = await supabase.from("contracts").delete().eq("id", id);
146	    if (error) {
147	      toast.error("Failed to delete contract");
148	      return;
149	    }
150	    toast.success("Contract deleted");
151	    fetchContracts();
152	  };
153	
154	  const handleDuplicate = async (contract: Contract) => {
155	    const { data: { session } } = await supabase.auth.getSession();
156	    if (!session) return;
157	
158	    const { error } = await supabase.from("contracts").insert({
159	      user_id: session.user.id,
160	      title: `${contract.title} (Copy)`,
161	      client_name: contract.client_name,
162	      client_email: contract.client_email,
163	      contract_type: contract.contract_type,
164	      content: contract.content,
165	      deliverables: contract.deliverables,
166	      payment_terms: contract.payment_terms,
167	      exclusivity: contract.exclusivity,
168	      exclusivity_details: contract.exclusivity_details,
169	      usage_rights: contract.usage_rights,
170	      termination_clause: contract.termination_clause,
171	      value: contract.value,
172	      currency: contract.currency,
173	      status: "draft",
174	    });
175	
176	    if (error) {
177	      toast.error("Failed to duplicate contract");
178	      return;
179	    }
180	    toast.success("Contract duplicated");
181	    fetchContracts();
182	  };
183	
184	  const handleStatusChange = async (id: string, status: string) => {
185	    const { error } = await supabase
186	      .from("contracts")
187	      .update({ status })
188	      .eq("id", id);
189	
190	    if (error) {
191	      toast.error("Failed to update status");
192	      return;
193	    }
194	    toast.success(`Status updated to ${status}`);
195	    fetchContracts();
196	  };
197	
198	  const handleFileUpload = async (file: File, contractType: string, title: string) => {
199	    const { data: { session } } = await supabase.auth.getSession();
200	    if (!session) return;
201	
202	    const fileExt = file.name.split(".").pop()?.toLowerCase();
203	    
204	    let content = "";
205	
206	    // For text-based files, read the content directly for editing
207	    if (fileExt === "txt" || fileExt === "md") {
208	      content = await file.text();
209	    } else {
210	      // For PDF, DOCX, etc. — upload to storage and create editable content
211	      const storagePath = `${session.user.id}/${Date.now()}-${file.name}`;
212	      
213	      const { error: uploadError } = await supabase.storage
214	        .from("contract-uploads")
215	        .upload(storagePath, file);
216	
217	      if (uploadError) {
218	        toast.error("Failed to upload file: " + uploadError.message);
219	        return;
220	      }
221	
222	      content = `[Original file: ${file.name}]\n[File type: ${file.type || fileExt}]\n[Uploaded: ${new Date().toLocaleString()}]\n\n---\n\nYou can edit this contract content below. The original document has been securely stored.\n\n---\n\n[Add or paste your contract terms here]`;
223	    }
224	
225	    const { data, error } = await supabase.from("contracts").insert({
226	      user_id: session.user.id,
227	      title,
228	      client_name: "To be specified",
229	      contract_type: contractType,
230	      content,
231	      status: "draft",
232	      currency: "KES",
233	    }).select().single();
234	
235	    if (error) {
236	      toast.error("Failed to create contract record");
237	      return;
238	    }
239	
240	    toast.success("Contract uploaded! You can now edit all details.");
241	    fetchContracts();
242	    
243	    // Open the edit dialog immediately so user can fill in details
244	    if (data) {
245	      setEditingContract(data as Contract);
246	    }
247	  };
248	
249	  const formatCurrency = (amount: number | null, currency: string) => {
250	    if (!amount) return "—";
251	    return new Intl.NumberFormat("en-KE", {
252	      style: "currency",
253	      currency: currency || "KES",
254	    }).format(amount);
255	  };
256	
257	  const filteredContracts = contracts
258	    .filter((contract) => {
259	      const matchesSearch = contract.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
260	        contract.client_name.toLowerCase().includes(searchQuery.toLowerCase());
261	      const matchesStatus = statusFilter === "all" || contract.status === statusFilter;
262	      return matchesSearch && matchesStatus;
263	    })
264	    .sort((a, b) => {
265	      if (sortBy === "value") return (Number(b.value) || 0) - (Number(a.value) || 0);
266	      if (sortBy === "oldest") return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
267	      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
268	    });
269	
270	  const stats = {
271	    total: contracts.length,
272	    active: contracts.filter((c) => c.status === "active" || c.status === "signed").length,
273	    pending: contracts.filter((c) => c.status === "sent" || c.status === "draft").length,
274	    totalValue: contracts.filter(c => c.status !== "cancelled").reduce((acc, c) => acc + (Number(c.value) || 0), 0),
275	  };
276	
277	  if (loading) {
278	    return (
279	      <div className="mx-auto w-full max-w-6xl space-y-8 p-4 md:p-8">
280	        <div className="animate-pulse space-y-8">
281	          <div className="h-10 bg-muted rounded-2xl w-1/3" />
282	          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
283	            {[...Array(4)].map((_, i) => (
284	              <div key={i} className="h-24 bg-muted rounded-2xl" />
285	            ))}
286	          </div>
287	          <div className="h-12 bg-muted rounded-2xl" />
288	          {[...Array(3)].map((_, i) => (
289	            <div key={i} className="h-20 bg-muted rounded-2xl" />
290	          ))}
291	        </div>
292	      </div>
293	    );
294	  }
295	
296	  return (
297	    <div className="mx-auto w-full max-w-6xl min-w-0 space-y-6 p-4 md:p-8 xl:max-w-7xl">
298	
299	      {/* Header — Clean & Minimal */}
300	      <motion.div 
301	        initial={{ opacity: 0, y: 8 }}
302	        animate={{ opacity: 1, y: 0 }}
303	        className="flex flex-col md:flex-row md:items-end justify-between gap-4"
304	      >
305	        <div>
306	          <h2 className="font-vollkorn text-3xl md:text-4xl font-bold text-foreground tracking-tight">
307	            Contracts
308	          </h2>
309	          <p className="text-sm text-muted-foreground mt-1">
310	            Professional agreements, e-signatures & document management
311	          </p>
312	        </div>
313	        <div className="flex items-center gap-2">
314	          <Button
315	            variant="outline"
316	            onClick={() => setUploadDialogOpen(true)}
317	            className="gap-2 h-10 rounded-xl border-dashed hover:border-bronze/50 hover:bg-bronze/5 transition-all"
318	          >
319	            <Upload className="h-4 w-4" />
320	            <span className="hidden sm:inline">Upload</span>
321	          </Button>
322	          <Button
323	            // onClick={() => setCreateDialogOpen(true)}
324	            onClick={async () => {
325	              if (isFree) {
326	                const { count } = await supabase
327	                  .from("contracts")
328	                  .select("*", { count: "exact", head: true });
329	                if ((count || 0) >= limits.contractsPerMonth) {
330	                  toast.error("You've reached your free plan limit of 5 contracts. Upgrade to Pro for unlimited contracts.");
331	                return;
332	              }
333	            } 
334	            setCreateDialogOpen(true);
335	          }}
336	            className="gap-2 h-10 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 transition-all hover:shadow-xl hover:shadow-primary/30"
337	          >
338	            <Plus className="h-4 w-4" />
339	            New Contract
340	          </Button>
341	        </div>
342	      </motion.div>
343	
344	      {/* Stats — Glass Morphism Cards */}
345	      <motion.div 
346	        initial={{ opacity: 0, y: 12 }}
347	        animate={{ opacity: 1, y: 0 }}
348	        transition={{ delay: 0.05 }}
349	        className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-4"
350	      >
351	        {[
352	          { label: "Total", value: stats.total, icon: <File className="h-4 w-4" />, accent: "primary" },
353	          { label: "Active", value: stats.active, icon: <CheckCircle2 className="h-4 w-4" />, accent: "emerald" },
354	          { label: "Pending", value: stats.pending, icon: <Clock className="h-4 w-4" />, accent: "amber" },
355	          { label: "Value", value: formatCurrency(stats.totalValue, "KES"), icon: <TrendingUp className="h-4 w-4" />, accent: "blue" },
356	        ].map((stat, i) => (
357	          <div
358	            key={stat.label}
359	            className="relative group p-4 rounded-2xl border border-border/50 bg-card hover:border-border transition-all overflow-hidden"
360	          >
361	            <div className={`absolute inset-0 bg-gradient-to-br opacity-0 group-hover:opacity-100 transition-opacity duration-500 ${
362	              stat.accent === "primary" ? "from-primary/5 to-transparent" :
363	              stat.accent === "emerald" ? "from-emerald-500/5 to-transparent" :
364	              stat.accent === "amber" ? "from-amber-500/5 to-transparent" :
365	              "from-blue-500/5 to-transparent"
366	            }`} />
367	            <div className="relative">
368	              <div className={`w-8 h-8 rounded-xl flex items-center justify-center mb-2 ${
